/**
 * Render and set config for custom POC IS.03 Grid
 * 
 * by Jhon Chacolla
 */

 let data = {
    IN_INVOICE_PRE_TAX: this.IN_INVOICE_PRE_TAX + "",
    IN_INVOICE_TAX_TOTAL: this.IN_INVOICE_TAX_TOTAL + "",
    IN_INVOICE_TOTAL: this.IN_INVOICE_TOTAL + "",

    IN_INVOICE_PRE_TAX_PERCENTAGE: this.IN_INVOICE_PRE_TAX_PERCENTAGE + "",
    IN_INVOICE_TAX_TOTAL_PERCENTAGE: this.IN_INVOICE_TAX_TOTAL_PERCENTAGE + "",
    IN_INVOICE_TOTAL_PERCENTAGE: this.IN_INVOICE_TOTAL_PERCENTAGE + "",

    IN_INVOICE_CURRENCY: this.IN_INVOICE_CURRENCY+"",

    IN_TOTAL_PRE_TAX_AMOUNT: this.IN_TOTAL_PRE_TAX_AMOUNT + "",
    IN_TOTAL_HST: this.IN_TOTAL_HST + "",
    IN_TOTAL_TOTAL: this.IN_TOTAL_TOTAL + "",
    IN_TOTAL_PERCENTAGE_TOTAL: this.IN_TOTAL_PERCENTAGE_TOTAL + "",
    IN_OUTSTANDING_TOTAL: this.IN_OUTSTANDING_TOTAL + "",
    IN_OUTSTANDING_PERCENTAGE: this.IN_OUTSTANDING_PERCENTAGE + "",

    IN_REQUEST_ID: this.IN_REQUEST_ID,

    IN_EXPENSE_REQUEST: this.IN_EXPENSE_REQUEST,
};
let jsonData = JSON.stringify(data);
//Encode data to make it secure
let encodedData = encodeURIComponent(jsonData);
//Get window height
let screenHeight = 508;
if (typeof top.innerHeight != 'undefined') {
    screenHeight = top.innerHeight - 250;
}
//let code = `<body style="margin:0px;padding:0px;overflow:hidden;width:` + screenHeight + `px">
let code = `<body style="margin:0px;padding:0px;">
    <style>
        .iframe-container {
            background:url(/public-files/loadingIMG.gif) center center no-repeat;
        }
    </style>
    <div class="iframe-container">
        <iframe id="iframe-psTools"
            src="/api/1.0/pstools/script/poc-dhs01-custom-grid-iframe-view-mode?data=` + encodedData + `" frameborder="0" 
            style="overflow:hidden;overflow-x:hidden;overflow-y:hidden;height:` + screenHeight + `px;
            width:100%; top:110px;left:0px;right:0px;bottom:0px" 
        ></iframe>
    </div>
</body>`;
return code;

/*
 *
 */

let totalPreTax = this.totalPreTaxAmount ?? 0;
let totalHst = this.totalHst ?? 0;
return parseFloat(totalPreTax) + parseFloat(totalHst);

let submitButtonFake = this.submitButtonFake;

let dataIframe = $('#iframe-psTools').contents().find('#iframe-items').val() ?? '';
if (dataIframe !='') {
    dataIframe = JSON.parse(dataIframe);
}
return dataIframe;

/**
 * Validate Custom iFrame Grid
 * 
 * by Jhon Chacolla
 */
let isValid = false;
let fakeSubmit = this.submitButtonFake;
console.log('fakeSubmit',fakeSubmit);
let totalFinalAmount = $('#iframe-psTools').contents().find('#iframe-totalFinalAmount').val() ?? 0;
console.log('PM totalFinalAmount-> ', totalFinalAmount);
if (this.totalAmount == totalFinalAmount && totalFinalAmount != 0 && typeof(totalFinalAmount) != 'undefined' && fakeSubmit != null) {
    isValid = true;
}

if (isValid === true) {
    $('[selector="fakeSubmitButton"] > div > button'). attr("disabled", true);
    ProcessMaker.alert('Your request is being processed', "success");
    setTimeout(function () {
        $('[selector="submitButton"] > div > button').click()
        $('[selector="fakeSubmitButton"] > div > button'). attr("disabled", false);
    }, 2500);
}

return isValid;

